    callWithHandle {
    uniffiRustCall() { _status ->
    UniffiLib.uniffi_danchor_ffi_fn_method_framereassemblerffi_insert(
        it,
        
        FfiConverterTypeVideoFragmentFfi.lower(`fragment`),_status)
}
    }
    )
    }
    

    

    


    
    
    /**
     * @suppress
     */
    companion object
    
}


